import { describe, it, expect } from 'vitest';
import { formatDate } from './path/to/module'; // adjust import path

describe('formatDate', () => {
  it('should handle happy path', () => {
    const iso = '2023-07-15T12:34:56Z';
    const result = formatDate(iso);
    expect(result).toBe('July 15, 2023 at 12:34 PM');
  });

  it('should handle edge case', () => {
    const iso = '2020-02-29T00:00:00Z'; // leap day
    const result = formatDate(iso);
    expect(result).toBe('February 29, 2020 at 12:00 AM');
  });

  it('should handle null/empty', () => {
    expect(formatDate(null)).toBe('Invalid Date');
    expect(formatDate(undefined)).toBe('Invalid Date');
    expect(formatDate('')).toBe('Invalid Date');
    expect(formatDate(0 as unknown as string)).toBe('Invalid Date');
  });
});

